///SB, DLT, 30/04/2026
/// <summary>
/// COC of standard method to add custom BatchId
/// </summary>
void initFromCaller(Args args)
{
    FormControl     selectedControl;
    FormRun         callerForm;
    int             h;

    callerForm  = args.caller();
    selectedControl = callerForm.selectedControl();

    next initFromCaller(args);

    if (callerForm.name() == formStr(EcoResProductDetailsExtended) && selectedControl.name() == formControlStr(EcoResProductDetailsExtended, ETGDefaultBatchNumber))
    {
        for (h = 1; h <= callerForm.dataSourceCount(); h++)
        {
            if (callerForm.dataSource(h).cursor().TableId == tableNum(InventTable))
            {
                this.initFromETGInventTable(callerForm.dataSource(h).cursor() as InventTable);
                return;
            }
        }
    }
}

///SB, DLT, 30/04/2026
/// <summary>
/// method to support above customisation
/// </summary>
void initFromETGInventTable(InventTable inventTable)
{
    this.ItemId = inventTable.ItemId;
}
